                c->col_idx[ptr] = bj;
                for (int r = 0; r < bs; r++) {
                    for (int cc = 0; cc < bs; cc++) {
                        int gr = row_blk * bs + r;
                        int gc = col_blk * bs + cc;
                        c->data[ptr * bs * bs + r * bs + cc] = a->a[gr * dim + gc];
                    }
                }
                ptr++;
            }
        }
    }
    c->row_ptr[nb] = ptr;

    // Diagonal preconditioner in packed indexing.
    for (int i = 0; i < dim; i++) {
        c->diag_inv[i] = 1.0;
    }
    for (int bi = 0; bi < nb; bi++) {
        int start = c->row_ptr[bi];
        int end = c->row_ptr[bi + 1];
        for (int k = start; k < end; k++) {
            if (c->col_idx[k] == bi) {
                for (int r = 0; r < bs; r++) {
                    double d = c->data[k * bs * bs + r * bs + r];
                    if (fabs(d) > 1e-14) {
                        c->diag_inv[bi * bs + r] = 1.0 / d;
                    }
                }
            }
        }
    }
}

void bsr_matvec(const BsrPack *pack, const double *x, double *y) {
    int nb = pack->nblocks;
    int bs = pack->bs;
    int dim = pack->n;
    for (int i = 0; i < dim; i++) {
        y[i] = 0.0;
    }
    for (int bi = 0; bi < nb; bi++) {
        int start = pack->row_ptr[bi];
        int end = pack->row_ptr[bi + 1];
        for (int k = start; k < end; k++) {
            int bj = pack->col_idx[k];
            for (int r = 0; r < bs; r++) {
                for (int ccc = 0; ccc < bs; ccc++) {
                    int gi = bi * bs + r;
                    int gj = bj * bs + ccc;
                    y[gi] += pack->data[k * bs * bs + r * bs + ccc] * x[gj];
                }
            }
        }
    }
}
