// Map a vector from original ordering to packed ordering.
// When reorder is enabled, packed block index bi corresponds to original block perm[bi].
void map_p(const double *in, const int *perm, int n, int bs, double *out) {
    int nb = n / bs;
    // Default: identity mapping.
    for (int i = 0; i < n; i++) {
        out[i] = in[i];
    }

    // If perm is present and differs, map by blocks.
    // out[bi] = in[perm[bi]] (block-wise)
    // This matches fn_n building rows in packed order.
    if (perm) {
        for (int bi = 0; bi < nb; bi++) {
            int src_blk = perm[bi];
            memcpy(out + bi * bs, in + src_blk * bs, (size_t)bs * sizeof(double));
        }
    }
}
